content:
{
  "sentences": [
    {
      "text": "我正在開會，等一下再討論這個提案。",
      "pinyin": "Wǒ zhèngzài kāihuì, děng yīxià zài tǎolùn zhège tí'àn.",
      "pinyin_numeric": "wo3 zheng4zai4 kai1hui4, deng3 yi1xia4 zai4 tao3lun4 zhe4ge ti2'an4.",
      "translation_en": "I am in a meeting right now; let's discuss this proposal later.",
      "translation_ko": "지금 회의 중이에요. 이 제안은 나중에 논의해요."
    },
    {
      "text": "他們在討論進度，但是還沒有決定。",
      "pinyin": "Tāmen zài tǎolùn jìndù, dànshì hái méiyǒu juédìng.",
      "pinyin_numeric": "ta1men zai4 tao3lun4 jin4du4, dan4shi4 hai2 mei2you3 jue2ding4.",
      "translation_en": "They are discussing the progress, but they haven't decided yet.",
      "translation_ko": "그들은 진행 상황을 논의 중이지만 아직 결정하지 않았어요."
    },
    {
      "text": "老闆在檢查報告，所以我們在等他的意見。",
      "pinyin": "Lǎobǎn zài jiǎnchá bàogào, suǒyǐ wǒmen zài děng tā de yìjiàn.",
      "pinyin_numeric": "lao3ban3 zai4 jian3cha2 bao4gao4, suo3yi3 wo3men zai4 deng3 ta1 de yi4jian4.",
      "translation_en": "The boss is checking the report, so we are waiting for his opinion.",
      "translation_ko": "사장님이 보고서를 확인 중이라서 우리는 그의 의견을 기다리고 있어요."
    },
    {
      "text": "你在填寫表格嗎？我已經完成了。",
      "pinyin": "Nǐ zài tiánxiě biǎogé ma? Wǒ yǐjīng wánchéng le.",
      "pinyin_numeric": "ni3 zai4 tian2xie3 biao3ge2 ma0? wo3 yi3jing1 wan2cheng2 le5.",
      "translation_en": "Are you filling out the form? I have already finished.",
      "translation_ko": "표를 작성 중이신가요? 저는 이미 완료했어요."
    },
    {
      "text": "他們在開會討論目標，我們必須準時參加。",
      "pinyin": "Tāmen zài kāihuì tǎolùn mùbiāo, wǒmen bìxū zhǔnshí cānjiā.",
      "pinyin_numeric": "ta1men zai4 kai1hui4 tao3lun4 mu4biao1, wo3men bi4xu1 zhun3shi2 can1jia1.",
      "translation_en": "They are having a meeting to discuss the goals; we must attend on time.",
      "translation_ko": "그들이 목표를 논의하는 회의 중이에요. 우리는 정시에 참석해야 해요."
    },
    {
      "text": "因為任務的截止日期快到了，所以大家都在趕進度。",
      "pinyin": "Yīnwèi rènwù de jiézhǐ rìqī kuài dào le, suǒyǐ dàjiā dōu zài gǎn jìndù.",
      "pinyin_numeric": "yin1wei4 ren4wu4 de5 jie2zhi3 ri4qi1 kuai4 dao4 le5, suo3yi3 da4jia1 dou1 zai4 gan3 jin4du4.",
      "translation_en": "Because the deadline for the task is approaching, everyone is rushing to meet the progress.",
      "translation_ko": "임무 마감일이 다가오고 있어서 모두가 진도를 서두르고 있어요."
    },
    {
      "text": "我們在整理資料，然後再修改檔案。",
      "pinyin": "Wǒmen zài zhěnglǐ zīliào, ránhòu zài xiūgǎi dǎng'àn.",
      "pinyin_numeric": "wo3men zai4 zheng3li3 zi1liao4, ran2hou4 zai4 xiu1gai3 dang3'an4.",
      "translation_en": "We are organizing the data, and then we will revise the files.",
      "translation_ko": "자료를 정리 중이고, 그다음에 파일을 수정할 거예요."
    },
    {
      "text": "他正在簽名確認訂單，所以請等一下。",
      "pinyin": "Tā zhèngzài qiānmíng quèrèn dìngdān, suǒyǐ qǐng děng yīxià.",
      "pinyin_numeric": "ta1 zheng4zai4 qian1ming2 que4ren4 ding4dan1, suo3yi3 qing3 deng3 yi1xia4.",
      "translation_en": "He is signing to confirm the order, so please wait a moment.",
      "translation_ko": "그가 주문을 확인하며 서명 중이니 잠시 기다려 주세요."
    },
    {
      "text": "你們在討論什麼？這個提案很重要。",
      "pinyin": "Nǐmen zài tǎolùn shénme? Zhège tí'àn hěn zhòngyào.",
      "pinyin_numeric": "ni3men zai4 tao3lun4 shen2me0? zhe4ge ti2'an4 hen3 zhong4yao4.",
      "translation_en": "What are you discussing? This proposal is very important.",
      "translation_ko": "무엇을 논의 중이신가요? 이 제안은 매우 중요해요."
    },
    {
      "text": "因為會議延長了，所以我們必須提早完成報告。",
      "pinyin": "Yīnwèi huìyì yáncháng le, suǒyǐ wǒmen bìxū tízǎo wánchéng bàogào.",
      "pinyin_numeric": "yin1wei4 hui4yi4 yan2chang2 le5, suo3yi3 wo3men bi4xu1 ti2zao3 wan2cheng2 bao4gao4.",
      "translation_en": "Because the meeting has been extended, we must finish the report early.",
      "translation_ko": "회의가 연장되었기 때문에 우리는 보고서를 일찍 완료해야 해요."
    }
  ]
}
